const e={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Modifiez en toute sécurité la configuration de l'écran tactile KlipperScreen de votre imprimante, puis redémarrez KlipperScreen pour l'appliquer. Chaque enregistrement est sauvegardé au préalable."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Comment ça marche"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf contrôle l'écran tactile relié à votre imprimante — thème, langue, menus et options d'affichage. Cet éditeur lit et écrit ce fichier via le même chemin sécurisé que l'Éditeur de config."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Modifiez le texte de configuration ci-dessous (ou laissez-le tel quel)."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrez — le fichier est d'abord sauvegardé, et l'enregistrement est refusé pendant que l'imprimante est occupée."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrez KlipperScreen pour appliquer le changement sur l'écran physique."}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"Les lignes utilisent des fins de ligne UNIX (LF), imposées automatiquement à l'enregistrement."}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"Recherche de KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen n'a pas été détecté sur cette imprimante (pas de KlipperScreen.conf, et non signalé par Moonraker). Installez KlipperScreen pour utiliser cet outil."}},present:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen détecté"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"Thème"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Langue"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker ne peut pas redémarrer KlipperScreen automatiquement — redémarrez-le manuellement après l'enregistrement."}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lecture de KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"Recharger"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrer la config"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrement…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"Enregistré (sauvegardé)"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Modifications non enregistrées"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"Refusé pendant que l'imprimante est occupée — réessayez quand elle est inactive."}},stale:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf a changé sur le disque depuis son chargement (probablement modifié sur l'écran). Rechargez avant d'enregistrer pour ne pas écraser ce changement."}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer KlipperScreen"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrage…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen redémarre — l'écran se rechargera sous peu."}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer KlipperScreen ?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Cela redémarre le service de l'écran tactile pour appliquer vos changements. Cela n'affecte pas une impression en cours, mais l'écran s'éteindra quelques secondes."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}}}}};export{e as default};
